/* =========================== Venn widget =========================== */
(function(){
  const svg = $('#venn-svg'), out = $('#venn-out');
  const clearBtn = $('#venn-clear'), randBtn = $('#venn-rand');
  const N = 8;
  // state[i] ∈ {0: out, 1: A only, 2: B only, 3: both}
  let state = [0,0,0,0,0,0,0,0];

  // Fixed pixel positions for the 8 elements inside the two overlapping circles.
  // Circle A centered at (230, 160), r=110. Circle B centered at (390, 160), r=110.
  // We assign elements to named regions; user clicking cycles membership.
  const POS = [
    [170, 110], // 1 — A only (upper)
    [170, 210], // 2 — A only (lower)
    [225, 160], // 3 — A only (center)
    [310,  98], // 4 — intersection (top)
    [310, 160], // 5 — intersection (middle)
    [310, 222], // 6 — intersection (bottom)
    [395, 160], // 7 — B only (center)
    [460, 160], // 8 — B only (right)
  ];

  function regionColor(s){
    if(s===1) return 'var(--blue)';
    if(s===2) return 'var(--yellow)';
    if(s===3) return 'var(--green)';
    return 'var(--panel2)';
  }
  function regionText(s){
    if(s===1) return '#0b0d10';
    if(s===2) return '#0b0d10';
    if(s===3) return '#0b0d10';
    return 'var(--mute)';
  }

  function render(){
    svg.innerHTML='';
    // outer universe rect
    svg.appendChild(SVG('rect',{x:20, y:20, width:580, height:280, rx:12, ry:12,
      fill:'rgba(154,164,178,0.04)', stroke:'var(--line)', 'stroke-dasharray':'4 4'}));
    const u = SVG('text',{x:44, y:46,'font-size':13, fill:'var(--mute)'});
    u.textContent = 'U'; svg.appendChild(u);
    // two circles
    svg.appendChild(SVG('circle',{cx:230, cy:160, r:110, fill:'rgba(88,196,221,0.10)',
      stroke:'var(--blue)', 'stroke-width':1.5}));
    svg.appendChild(SVG('circle',{cx:390, cy:160, r:110, fill:'rgba(255,216,102,0.10)',
      stroke:'var(--yellow)', 'stroke-width':1.5}));
    // circle labels
    const la = SVG('text',{x:148, y:66,'font-size':18, fill:'var(--blue)','font-weight':700});
    la.textContent='A'; svg.appendChild(la);
    const lb = SVG('text',{x:460, y:66,'font-size':18, fill:'var(--yellow)','font-weight':700});
    lb.textContent='B'; svg.appendChild(lb);
    // element cells
    for(let i=0;i<N;i++){
      const [x,y] = POS[i];
      const s = state[i];
      svg.appendChild(SVG('circle',{cx:x, cy:y, r:16, fill:regionColor(s),
        stroke:'var(--ink)', 'stroke-width': s? 2 : 1,
        style:'cursor:pointer', 'data-idx': String(i)}));
      const t = SVG('text',{x, y:y+4,'text-anchor':'middle','font-size':13,
        fill: regionText(s), 'font-weight':700, 'pointer-events':'none'});
      t.textContent = String(i+1);
      svg.appendChild(t);
    }
    // legend
    const lgY = 298;
    const legend = [
      [40, lgY, 'var(--panel2)', 'out'],
      [110, lgY, 'var(--blue)', 'only $A$'],
      [195, lgY, 'var(--yellow)', 'only $B$'],
      [285, lgY, 'var(--green)', '$A\\cap B$'],
    ];
    // (plain-text fallback inside svg — katex does not typeset inside SVG)
    const lg = ['out', 'A only', 'B only', 'A∩B'];
    [40,108,188,278].forEach((x,i)=>{
      svg.appendChild(SVG('circle',{cx:x, cy:lgY, r:7,
        fill: i===0?'var(--panel2)': i===1?'var(--blue)': i===2?'var(--yellow)':'var(--green)',
        stroke:'var(--ink)','stroke-width':1}));
      const t=SVG('text',{x:x+12, y:lgY+4,'font-size':11, fill:'var(--mute)'});
      t.textContent = lg[i];
      svg.appendChild(t);
    });
    renderReadout();
  }

  function renderReadout(){
    const A = [], B = [];
    for(let i=0;i<N;i++){
      if(state[i]===1 || state[i]===3) A.push(i+1);
      if(state[i]===2 || state[i]===3) B.push(i+1);
    }
    const setS = arr => arr.length? '{'+arr.join(',')+'}' : '∅';
    const inter = A.filter(x=>B.includes(x));
    const union = [...new Set([...A,...B])].sort((a,b)=>a-b);
    const diffAB = A.filter(x=>!B.includes(x));
    const diffBA = B.filter(x=>!A.includes(x));
    const sym = [...diffAB, ...diffBA].sort((a,b)=>a-b);
    const compA = [];
    for(let i=1;i<=N;i++) if(!A.includes(i)) compA.push(i);

    const lines = [
      `A          = ${setS(A)}       |A|          = ${A.length}`,
      `B          = ${setS(B)}       |B|          = ${B.length}`,
      `A ∩ B      = ${setS(inter)}       |A ∩ B|      = ${inter.length}`,
      `A ∪ B      = ${setS(union)}       |A ∪ B|      = ${union.length}`,
      `A \\ B      = ${setS(diffAB)}       |A \\ B|      = ${diffAB.length}`,
      `A △ B      = ${setS(sym)}       |A △ B|      = ${sym.length}`,
      `A^c (in U) = ${setS(compA)}       |A^c|        = ${compA.length}`,
      ``,
      `check: |A∪B| = |A| + |B| − |A∩B|   →   ${union.length} = ${A.length} + ${B.length} − ${inter.length}   ${union.length === A.length + B.length - inter.length ? '✓' : '✗'}`,
      `check: |A△B| = |A∪B| − |A∩B|       →   ${sym.length} = ${union.length} − ${inter.length}   ${sym.length === union.length - inter.length ? '✓' : '✗'}`,
    ];
    out.textContent = lines.join('\n');
  }

  svg.addEventListener('click', (e)=>{
    const idx = e.target && e.target.getAttribute && e.target.getAttribute('data-idx');
    if(idx === null || idx === undefined) return;
    const i = parseInt(idx,10);
    state[i] = (state[i]+1) % 4;
    render();
  });
  clearBtn.addEventListener('click', ()=>{ state = state.map(()=>0); render(); });
  randBtn.addEventListener('click', ()=>{ state = state.map(()=>Math.floor(Math.random()*4)); render(); });
  render();
})();

