const nAsel=$('#fn-nA'), nBsel=$('#fn-nB'), rand=$('#fn-rand'), idBtn=$('#fn-id');
const picker=$('#fn-picker'), svg=$('#fn-svg'), out=$('#fn-out');
let nA=3, nB=3, f=[0,1,2];
const aLabel = i => 'a'+(i+1);
const bLabel = j => 'b'+(j+1);

function fit(){
  while(f.length<nA) f.push(0);
  f = f.slice(0,nA).map(v=>Math.min(Math.max(v,0), nB-1));
}
function buildPicker(){
  picker.innerHTML='';
  const lab=document.createElement('span'); lab.className='small'; lab.style.color='var(--mute)';
  lab.textContent='function: ';
  picker.appendChild(lab);
  for(let i=0;i<nA;i++){
    const span=document.createElement('span');
    span.innerHTML=`<span class="small" style="color:var(--mute)">${aLabel(i)} ↦ </span>`;
    const sel=document.createElement('select'); sel.style.marginRight='.6rem';
    for(let j=0;j<nB;j++){
      const o=document.createElement('option'); o.value=j; o.textContent=bLabel(j);
      if(f[i]===j) o.selected=true;
      sel.appendChild(o);
    }
    sel.addEventListener('change',()=>{f[i]=parseInt(sel.value,10); render();});
    span.appendChild(sel);
    picker.appendChild(span);
  }
}
function render(){
  svg.innerHTML='';
  const W=620, H=280;
  const xL=180, xR=440;
  const spacing=46;
  const yMid=H/2;
  const aYs=[]; for(let i=0;i<nA;i++) aYs.push(yMid + (i - (nA-1)/2)*spacing);
  const bYs=[]; for(let j=0;j<nB;j++) bYs.push(yMid + (j - (nB-1)/2)*spacing);
  const yTopA = Math.min(...aYs)-30, yBotA = Math.max(...aYs)+30;
  const yTopB = Math.min(...bYs)-30, yBotB = Math.max(...bYs)+30;
  svg.appendChild(SVG('rect',{x:xL-60, y:yTopA, width:120, height:yBotA-yTopA, rx:14, ry:14,
    fill:'rgba(88,196,221,0.08)', stroke:'var(--blue)', 'stroke-dasharray':'4 4'}));
  svg.appendChild(SVG('rect',{x:xR-60, y:yTopB, width:120, height:yBotB-yTopB, rx:14, ry:14,
    fill:'rgba(255,216,102,0.08)', stroke:'var(--yellow)', 'stroke-dasharray':'4 4'}));
  const tA=SVG('text',{x:xL, y:yTopA-10,'text-anchor':'middle','font-size':14, fill:'var(--blue)','font-weight':700});
  tA.textContent='A'; svg.appendChild(tA);
  const tB=SVG('text',{x:xR, y:yTopB-10,'text-anchor':'middle','font-size':14, fill:'var(--yellow)','font-weight':700});
  tB.textContent='B'; svg.appendChild(tB);
  // compute image/hit counts
  const hitCount = Array(nB).fill(0);
  for(let i=0;i<nA;i++) hitCount[f[i]]++;
  // dots
  for(let i=0;i<nA;i++){
    svg.appendChild(SVG('circle',{cx:xL, cy:aYs[i], r:7, fill:'var(--blue)'}));
    const t=SVG('text',{x:xL-20, y:aYs[i]+5,'text-anchor':'end','font-size':13,fill:'#fff'});
    t.textContent=aLabel(i); svg.appendChild(t);
  }
  for(let j=0;j<nB;j++){
    const unhit = hitCount[j]===0;
    svg.appendChild(SVG('circle',{cx:xR, cy:bYs[j], r:7,
      fill:unhit?'var(--panel2)':'var(--yellow)',
      stroke: unhit?'var(--mute)':'var(--yellow)', 'stroke-width':1.5}));
    const t=SVG('text',{x:xR+20, y:bYs[j]+5,'text-anchor':'start','font-size':13,
      fill: unhit?'var(--mute)':'#fff'});
    t.textContent=bLabel(j); svg.appendChild(t);
  }
  // arrows
  ensureArrow(svg,'fn-arr','var(--violet)');
  for(let i=0;i<nA;i++){
    const j=f[i];
    const collision = hitCount[j] > 1;
    const color = collision ? 'var(--pink)' : 'var(--violet)';
    const mid = 'fn-arr-' + (collision?'coll':'ok');
    ensureArrow(svg, mid, color);
    const p=SVG('path',{d:`M${xL+10} ${aYs[i]} C ${xL+120} ${aYs[i]}, ${xR-120} ${bYs[j]}, ${xR-10} ${bYs[j]}`,
      fill:'none', stroke:color, 'stroke-width':1.6, 'marker-end':`url(#${mid})`});
    svg.appendChild(p);
  }
  // classify
  const image = [...new Set(f)];
  const injective = image.length === f.length;
  const surjective = image.length === nB;
  const bijective = injective && surjective;
  const verdict = bijective ? 'BIJECTIVE'
                  : injective ? 'injective (not surjective)'
                  : surjective ? 'surjective (not injective)'
                  : 'neither injective nor surjective';
  let why = '';
  if(!injective){
    // find a collision
    for(let j=0;j<nB;j++){
      if(hitCount[j]>1){
        const inputs=[];
        for(let i=0;i<nA;i++) if(f[i]===j) inputs.push(aLabel(i));
        why += `  ✗ injectivity fails: ${inputs.join(', ')} all map to ${bLabel(j)}\n`;
        break;
      }
    }
  } else {
    why += `  ✓ injective: no collisions\n`;
  }
  if(!surjective){
    for(let j=0;j<nB;j++){
      if(hitCount[j]===0){ why += `  ✗ surjectivity fails: ${bLabel(j)} is never hit\n`; break; }
    }
  } else {
    why += `  ✓ surjective: every b in B is in the image\n`;
  }
  out.textContent =
    `f : A → B,  |A|=${nA}, |B|=${nB}\n` +
    `f = { ${f.map((j,i)=>`${aLabel(i)}↦${bLabel(j)}`).join(',  ')} }\n` +
    `image = {${image.map(bLabel).join(',')}}  (size ${image.length})\n\n` +
    `${verdict}\n${why}` +
    (nA!==nB ? `\nnote: |A|=${nA} ≠ |B|=${nB}, so a bijection is impossible regardless of f.` : '');
}
function rebuild(){
  nA=parseInt(nAsel.value,10); nB=parseInt(nBsel.value,10);
  fit(); buildPicker(); render();
}
nAsel.addEventListener('change', rebuild);
nBsel.addEventListener('change', rebuild);
rand.addEventListener('click', ()=>{
  f = Array.from({length:nA}, ()=>Math.floor(Math.random()*nB));
  buildPicker(); render();
});
idBtn.addEventListener('click', ()=>{
  const n = Math.min(nA,nB);
  f = Array.from({length:nA}, (_,i)=> i<n ? i : 0);
  buildPicker(); render();
});
rebuild();

