/* =========================== Equivalence widget =========================== */
(function(){
  const svg=$('#eq-svg'), out=$('#eq-out');
  const resetBtn=$('#eq-reset'), m3=$('#eq-mod3'), m4=$('#eq-mod4'), triv=$('#eq-trivial');
  const N=12;
  // union-find
  let parent = Array.from({length:N}, (_,i)=>i);
  function find(i){ while(parent[i]!==i){ parent[i]=parent[parent[i]]; i=parent[i]; } return i; }
  function union(i,j){ const ri=find(i), rj=find(j); if(ri!==rj) parent[ri]=rj; }
  function reset(){ parent = Array.from({length:N}, (_,i)=>i); }

  // state for pending first click
  let picked = -1;

  // layout: 12 cells in 3 rows of 4
  const COLS=6, ROWS=2;
  const CELL=70;
  const X0=60, Y0=30;
  function cellPos(i){
    const r=Math.floor(i/COLS), c=i%COLS;
    return [X0 + c*CELL + CELL/2, Y0 + r*CELL + CELL/2];
  }

  // assign a color per root, stable across renders
  const PALETTE = ['var(--blue)','var(--yellow)','var(--green)','var(--pink)',
                   '--violet-bg','--cyan-bg','#e8a87c','#a1c6ea','#b8d8be','#d9b382','#c2b2e8','#f3a7c1'];
  const RESOLVE = ['var(--blue)','var(--yellow)','var(--green)','var(--pink)',
                   'var(--violet)','var(--cyan)','#e8a87c','#a1c6ea','#b8d8be','#d9b382','#c2b2e8','#f3a7c1'];

  function render(){
    svg.innerHTML='';
    // compute class roots in order of first appearance
    const rootOrder = [];
    const rootOfIdx = [];
    for(let i=0;i<N;i++){
      const r = find(i); rootOfIdx.push(r);
      if(!rootOrder.includes(r)) rootOrder.push(r);
    }
    // draw cells
    for(let i=0;i<N;i++){
      const [x,y] = cellPos(i);
      const classIdx = rootOrder.indexOf(rootOfIdx[i]);
      const color = RESOLVE[classIdx % RESOLVE.length];
      const isPicked = (i===picked);
      svg.appendChild(SVG('rect',{x:x-28, y:y-22, width:56, height:44, rx:9, ry:9,
        fill: color, stroke: isPicked ? 'var(--ink)' : 'transparent',
        'stroke-width': isPicked ? 3 : 0,
        style:'cursor:pointer', 'data-idx': String(i)}));
      const t = SVG('text',{x, y:y+5,'text-anchor':'middle','font-size':16,
        fill:'#0b0d10','font-weight':700,'pointer-events':'none'});
      t.textContent = String(i+1);
      svg.appendChild(t);
    }
    // classes summary
    const classes = rootOrder.map(r => {
      const members = [];
      for(let i=0;i<N;i++) if(find(i)===r) members.push(i+1);
      return members;
    });
    let body = `X = {1,2,…,12}\nclasses (${classes.length}):\n`;
    classes.forEach((c,i)=>{
      const rep = Math.min(...c);
      body += `  [${rep}] = {${c.join(',')}}   (size ${c.length})\n`;
    });
    body += `\n|X/∼| = ${classes.length}\n`;
    body += `π : X → X/∼,   n ↦ [n]\n`;
    body += `\nuniversal property: a function f:X→Y factors through π iff f is constant on classes.\n`;
    // a little sanity: check the reflexive/symmetric/transitive axioms are satisfied (they are, by construction).
    body += `(reflexive ✓ symmetric ✓ transitive ✓ — guaranteed by union-find.)`;
    out.textContent = body;
  }

  svg.addEventListener('click', (e)=>{
    const idx = e.target && e.target.getAttribute && e.target.getAttribute('data-idx');
    if(idx === null || idx === undefined) return;
    const i = parseInt(idx,10);
    if(picked === -1){ picked = i; render(); return; }
    if(picked === i){ picked = -1; render(); return; }
    union(picked, i);
    picked = -1;
    render();
  });
  resetBtn.addEventListener('click', ()=>{ reset(); picked=-1; render(); });
  m3.addEventListener('click', ()=>{
    reset();
    for(let i=1;i<N;i++) if(i%3 === 0 % 3) {} // no-op
    // group by n mod 3
    const bucket = {};
    for(let i=0;i<N;i++){
      const k = (i+1) % 3;
      if(bucket[k]===undefined) bucket[k]=i;
      else union(bucket[k], i);
    }
    picked=-1; render();
  });
  m4.addEventListener('click', ()=>{
    reset();
    const bucket={};
    for(let i=0;i<N;i++){
      const k=(i+1)%4;
      if(bucket[k]===undefined) bucket[k]=i;
      else union(bucket[k], i);
    }
    picked=-1; render();
  });
  triv.addEventListener('click', ()=>{
    reset();
    for(let i=1;i<N;i++) union(0,i);
    picked=-1; render();
  });
  render();
})();

