/* =========================== Cantor diagonal widget =========================== */
(function(){
  const svg=$('#diag-svg'), out=$('#diag-out');
  const prev=$('#diag-prev'), next=$('#diag-next'), reroll=$('#diag-reroll');
  const stepLbl=$('#diag-step');
  const ROWS=8, COLS=8;
  let list = makeList();
  let step = 0;  // 0 .. ROWS; step k means the first k diagonal bits are shown flipped

  function makeList(){
    const L = [];
    for(let i=0;i<ROWS;i++){
      const row=[];
      for(let j=0;j<COLS;j++) row.push(Math.random()<0.5?0:1);
      L.push(row);
    }
    return L;
  }
  function diagAt(i){ return 1 - list[i][i]; }

  function render(){
    svg.innerHTML='';
    const X0=60, Y0=30, CELL=30;
    // header
    const hdr = SVG('text',{x:X0 + COLS*CELL/2, y:Y0-10,'text-anchor':'middle','font-size':12,fill:'var(--mute)'});
    hdr.textContent = 'enumerated list of binary sequences s₀, s₁, …';
    svg.appendChild(hdr);
    // list rows
    for(let i=0;i<ROWS;i++){
      // row label
      const lab = SVG('text',{x:X0-10, y:Y0 + i*CELL + CELL/2 + 4,'text-anchor':'end','font-size':13,fill:'var(--mute)'});
      lab.textContent = 's'+i;
      svg.appendChild(lab);
      for(let j=0;j<COLS;j++){
        const bit = list[i][j];
        const onDiag = (i===j);
        const fillCell = onDiag ? 'rgba(255,216,102,0.18)' : 'var(--panel2)';
        const strokeCell = onDiag ? 'var(--yellow)' : 'var(--line)';
        svg.appendChild(SVG('rect',{x:X0 + j*CELL, y:Y0 + i*CELL, width:CELL-2, height:CELL-2,
          fill:fillCell, stroke:strokeCell, 'stroke-width': onDiag?1.5:1, rx:3}));
        const t=SVG('text',{x:X0 + j*CELL + CELL/2 - 1, y:Y0 + i*CELL + CELL/2 + 5,
          'text-anchor':'middle','font-size':14,
          fill: onDiag ? 'var(--yellow)' : 'var(--ink)',
          'font-family':'ui-monospace, monospace',
          'font-weight': onDiag ? 700 : 400});
        t.textContent = String(bit);
        svg.appendChild(t);
      }
    }
    // bottom: d row. shows flipped bits for positions < step, blanks beyond.
    const dY = Y0 + ROWS*CELL + 26;
    const dLab = SVG('text',{x:X0-10, y:dY + CELL/2 + 4,'text-anchor':'end','font-size':13,fill:'var(--pink)','font-weight':700});
    dLab.textContent='d';
    svg.appendChild(dLab);
    for(let j=0;j<COLS;j++){
      const shown = j < step;
      svg.appendChild(SVG('rect',{x:X0 + j*CELL, y:dY, width:CELL-2, height:CELL-2,
        fill: shown ? 'var(--pink)' : 'var(--panel2)',
        stroke: shown ? 'var(--pink)' : 'var(--line)', 'stroke-width':1.2, rx:3}));
      const t=SVG('text',{x:X0 + j*CELL + CELL/2 - 1, y:dY + CELL/2 + 5,
        'text-anchor':'middle','font-size':14,
        fill: shown ? '#0b0d10' : 'var(--mute)',
        'font-family':'ui-monospace, monospace','font-weight':700});
      t.textContent = shown ? String(diagAt(j)) : '?';
      svg.appendChild(t);
    }
    // arrow connecting current diagonal cell to d column
    if(step > 0 && step <= ROWS){
      const i = step-1, j = step-1;
      const from = [X0 + j*CELL + CELL/2, Y0 + i*CELL + CELL/2];
      const to   = [X0 + j*CELL + CELL/2, dY + CELL/2];
      drawArrow(svg, from, to, {color:'var(--pink)', markerId:'diag-flip', width:1.8,
        curve: 14, pad1:12, pad2:14});
    }
    // legend and captions
    const cap = SVG('text',{x:X0, y:dY + CELL + 24,'font-size':12,fill:'var(--mute)'});
    cap.textContent = 'd disagrees with sₙ in position n  ⇒  d ≠ sₙ for every n  ⇒  d is not on the list.';
    svg.appendChild(cap);

    stepLbl.textContent = step===0 ? 'step 0 of '+ROWS+' · press "next →" to start building d'
                      : step<ROWS ? `step ${step} of ${ROWS}` : `step ${ROWS} of ${ROWS} · d is complete`;
    prev.disabled = step===0;
    next.disabled = step>=ROWS;
    prev.style.opacity = prev.disabled? 0.5 : 1;
    next.style.opacity = next.disabled? 0.5 : 1;

    // readout
    const dFull = Array.from({length:COLS},(_,k)=>diagAt(k));
    const dShown = dFull.map((b,k)=> k<step ? String(b) : '·').join('');
    let msg = `list (${ROWS} sequences, first ${COLS} bits each):\n`;
    list.forEach((row,i)=>{
      const marked = row.map((b,j)=> j===i ? `[${b}]` : String(b)).join('');
      msg += `  s${i} = ${marked}\n`;
    });
    msg += `\nd[n] := 1 − sₙ(n)   →   d = ${dShown}`;
    if(step === ROWS){
      msg += `\n\nd differs from s₀ at position 0, from s₁ at position 1, …, from s${ROWS-1} at position ${ROWS-1}.`;
      msg += `\ntherefore d ∉ {s₀,…,s${ROWS-1}} — but by assumption the list contained every binary sequence.  ⇒  contradiction.`;
      msg += `\n\nconclusion: {0,1}^ℕ is uncountable.  |ℝ| ≥ |{0,1}^ℕ| > |ℕ| = |ℚ|.`;
    }
    out.textContent = msg;
  }

  next.addEventListener('click', ()=>{ if(step<ROWS){ step++; render(); } });
  prev.addEventListener('click', ()=>{ if(step>0){ step--; render(); } });
  reroll.addEventListener('click', ()=>{ list = makeList(); step = 0; render(); });
  render();
})();

