      msg += `  s${i} = ${marked}\n`;
    });
    msg += `\nd[n] := 1 − sₙ(n)   →   d = ${dShown}`;
    if(step === ROWS){
      msg += `\n\nd differs from s₀ at position 0, from s₁ at position 1, …, from s${ROWS-1} at position ${ROWS-1}.`;
      msg += `\ntherefore d ∉ {s₀,…,s${ROWS-1}} — but by assumption the list contained every binary sequence.  ⇒  contradiction.`;
      msg += `\n\nconclusion: {0,1}^ℕ is uncountable.  |ℝ| ≥ |{0,1}^ℕ| > |ℕ| = |ℚ|.`;
    }
    out.textContent = msg;
  }

  next.addEventListener('click', ()=>{ if(step<ROWS){ step++; render(); } });
  prev.addEventListener('click', ()=>{ if(step>0){ step--; render(); } });
  reroll.addEventListener('click', ()=>{ list = makeList(); step = 0; render(); });
  render();
})();
